```

### 3.4 Service Layer Modifications

#### 3.4.1 OrderService Changes

**File:** `src/main/java/com/commercesphere/enterprise/ordering/service/OrderService.java`

```java
@Service
@Validated
public class OrderService {

    private final OrderRepository orderRepository;
    private final PaymentOrchestrationService paymentOrchestrationService;
    // ... other dependencies ...

    /**
     * Creates a new order with idempotency guarantee.
     *
     * If an order with the given idempotencyKey already exists for this account,
     * returns the existing order instead of creating a new one.
     *
     * The implementation uses a "check-then-insert" pattern guarded by:
     * 1. A database UNIQUE constraint on (account_id, idempotency_key)
     * 2. A serializable transaction isolation level for the check
     *
     * @param request the order creation request
     * @return the created or existing order response
     */
    @Transactional(isolation = Isolation.SERIALIZABLE)
    public OrderResponse createOrder(@NotNull OrderCreateRequest request) {

        String idempotencyKey = request.idempotencyKey();

        // Step 1: Check for existing order with same idempotency key
        if (idempotencyKey != null && !idempotencyKey.isBlank()) {
            Optional<Order> existingOrder = orderRepository
                .findByCustomerIdAndIdempotencyKey(
                    request.customerId(),
                    idempotencyKey
                );

            if (existingOrder.isPresent()) {
                log.info("Returning existing order [{}] for idempotencyKey [{}]",
                    existingOrder.get().getId(), idempotencyKey);
                return toOrderResponse(existingOrder.get());
            }
        }

        // Step 2: Create and persist the new order with the idempotency key
        Order order = new Order();
        order.setCustomerId(request.customerId());
        order.setStatus(OrderStatus.DRAFT);
        order.setIdempotencyKey(idempotencyKey);  // Persist the key
        order.setCreatedAt(OffsetDateTime.now());
        // ... populate other fields ...

        try {
            Order persistedOrder = orderRepository.save(order);

            // Step 3: Process payment (using order's idempotency key)
            PaymentResult paymentResult = processPayment(
                persistedOrder,
                request.paymentInfo()
            );

            // Step 4: Update order status based on payment result
            if (paymentResult.isApproved()) {
                persistedOrder.setStatus(OrderStatus.PROCESSING);
                persistedOrder.setPaymentReference(paymentResult.getReference());
            }

            return toOrderResponse(orderRepository.save(persistedOrder));

        } catch (DataIntegrityViolationException e) {
            // Unique constraint violation - concurrent request won
            // Fetch and return the order created by the other request
            if (idempotencyKey != null) {
                return orderRepository
                    .findByCustomerIdAndIdempotencyKey(request.customerId(), idempotencyKey)
                    .map(this::toOrderResponse)
                    .orElseThrow(() -> new OrderCreationException(
                        "Concurrent order creation conflict", e));
            }
            throw e;
        }
    }
}
```

