@Transactional
public PaymentResponse authorize(PaymentRequest request, String clientIdempotencyKey) {
    validate(request);

    return retryTemplate.execute(context -> {
        acquireLock(request.getExternalOrderId());

        try {
            PaymentGateway gateway = gatewayRouter.route(request.getPaymentMethod());

            // Pass the client idempotency key to the gateway
            PaymentResponse response = gateway.authorize(request, clientIdempotencyKey);

            persistTransaction(request, response, PaymentIntent.AUTHORIZE, clientIdempotencyKey);

            return response;
        } finally {
            releaseLock();
        }
    });
}
```

